+    }
+
+    #[test]
+    fn no_trailing_slash_fails() {
+        let mut config = default_config();
+        config.http_path = "/mcp".into();
+        let result = probe_http_path(&config);
+        assert!(matches!(result, ProbeResult::Fail(_)));
+    }
+
+    #[test]
+    fn valid_http_path_passes() {
