+
+    #[test]
+    fn source_filter_restricts_view() {
+        let mut pane = test_pane();
+        pane.entries.push(TimelineEntry {
+            display: EventEntry {
+                kind: MailEventKind::HttpRequest,
+                severity: crate::tui_events::EventSeverity::Debug,
