+            seq: 1,
+            timestamp_micros: 1_000_000,
+            source: EventSource::Http,
+            severity: EventSeverity::Debug,
+            raw: make_event(1),
+        });
+        pane.entries.push(TimelineEntry {
+            display: EventEntry {
